import{_ as a,o as t,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"41. Special Disaster Leave","description":"","frontmatter":{"title":"41. Special Disaster Leave","eba":"Mental Health Services 2024-2028","topics":["leave","personal-leave"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/41-special-disaster-leave.md","filePath":"ebas/mental-health/common-terms/leave/41-special-disaster-leave.md"}'),o={name:"ebas/mental-health/common-terms/leave/41-special-disaster-leave.md"};function l(i,e,n,p,c,m){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="_41-special-disaster-leave" tabindex="-1">41. Special Disaster Leave <a class="header-anchor" href="#_41-special-disaster-leave" aria-label="Permalink to &quot;41. Special Disaster Leave&quot;">​</a></h1><p><strong>41.1</strong> Special disaster leave of up to 3 days per occasion is payable where:</p><p><strong>(a)</strong> The Employee is a full time or part time employee</p><p><strong>(b)</strong> Personal Leave is not available either because the Employee has exhausted the accrual or the circumstance does not qualify for Personal Leave; and</p><p><strong>(c)</strong> the Employee is unable to attend work due to a disaster (such as fire or flood) where:</p><p><strong>(i)</strong> the Employee&#39;s residence is damaged or under imminent threat of major damage</p><p><strong>(ii)</strong> the lives or safety of the Employee or a member of the Employee&#39;s immediate family or household is threatened; or</p><p><strong>(iii)</strong> there is a formal closure, flooding or other unusual danger of the use of a road(s) which is the Employee&#39;s normal travel route to work and no alternative practicable travel route is available.</p><p><strong>41.2</strong> Special disaster leave is non-cumulative.</p><p><strong>41.3</strong> Where requested by the Employer, the Employee must provide evidence that would satisfy a reasonable person of the reasons for accessing leave under this clause.</p><p>Plain language terms: disaster leave, emergency leave, flood leave, bushfire leave.</p>',11)])])}const v=a(o,[["render",l]]);export{h as __pageData,v as default};
